import React, { useEffect, useRef, useState } from 'react';
import './App.css';

const CITIES: string[] = [
  'Amsterdam', 'Ankara', 'Athens', 'Austin',
  'Barcelona', 'Berlin', 'Boston', 'Brussels',
  'Chicago', 'Copenhagen',
  'Dubai',
  'Edinburgh',
  'Frankfurt',
  'Hamburg',
  'Istanbul', 'Izmir',
  'London', 'Los Angeles',
  'Madrid', 'Miami', 'Milan', 'Munich',
  'New York',
  'Oslo',
  'Paris', 'Prague',
  'Rome',
  'San Diego', 'San Francisco', 'San Jose', 'Seattle', 'Seoul',
  'Tokyo',
  'Vienna',
  'Zurich'
];

type Status = 'idle' | 'loading' | 'success' | 'empty' | 'error';

function abortError(): DOMException {
  return new DOMException('Search aborted', 'AbortError');
}

function sleep(ms: number, signal: AbortSignal): Promise<void> {
  return new Promise((resolve, reject) => {
    let timerId: number | null = null;

    const cleanup = () => signal.removeEventListener('abort', onAbort);
    const onAbort = () => {
      if (timerId !== null) window.clearTimeout(timerId);
      cleanup();
      reject(abortError());
    };

    if (signal.aborted) {
      onAbort();
      return;
    }

    signal.addEventListener('abort', onAbort, { once: true });
    timerId = window.setTimeout(() => {
      cleanup();
      resolve();
    }, ms);
  });
}

function isAbortError(error: unknown): boolean {
  return error instanceof DOMException && error.name === 'AbortError';
}

function optionId(item: string): string {
  return 'autocomplete-option-' + item.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

export default function App() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const inputRef = useRef<HTMLInputElement | null>(null);
  const requestSeqRef = useRef(0);
  const selectedQueryRef = useRef('');

  const listboxId = 'autocomplete-listbox';
  const labelId = 'autocomplete-label';

  const [query, setQuery] = useState('');
  const [status, setStatus] = useState<Status>('idle');
  const [isOpen, setIsOpen] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);
  const [results, setResults] = useState<string[]>([]);

  useEffect(() => {
    const trimmed = query.trim();

    if (selectedQueryRef.current && selectedQueryRef.current === query) {
      selectedQueryRef.current = '';
      return;
    }

    if (!trimmed) {
      setResults([]);
      setStatus('idle');
      setIsOpen(false);
      setActiveIndex(-1);
      return;
    }

    let ignore = false;
    const controller = new AbortController();
    const requestId = ++requestSeqRef.current;

    setResults([]);
    setStatus('loading');
    setIsOpen(true);
    setActiveIndex(-1);

    const debounceId = window.setTimeout(async () => {
      try {
        const nextResults = await searchCities(trimmed, controller.signal);
        if (ignore || controller.signal.aborted || requestSeqRef.current !== requestId) return;
        setResults(nextResults);
        setStatus(nextResults.length ? 'success' : 'empty');
        setIsOpen(true);
        setActiveIndex(-1);
      } catch (error) {
        if (
          ignore ||
          controller.signal.aborted ||
          requestSeqRef.current !== requestId ||
          isAbortError(error)
        ) return;
        setResults([]);
        setStatus('error');
        setIsOpen(true);
        setActiveIndex(-1);
      }
    }, 300);

    return () => {
      ignore = true;
      controller.abort();
      window.clearTimeout(debounceId);
    };
  }, [query]);

  useEffect(() => {
    function onDocumentPointerDown(event: PointerEvent) {
      const root = rootRef.current;
      const target = event.target as Node | null;
      if (!root || !target || root.contains(target)) return;
      setIsOpen(false);
      setActiveIndex(-1);
    }

    document.addEventListener('pointerdown', onDocumentPointerDown);
    return () => document.removeEventListener('pointerdown', onDocumentPointerDown);
  }, []);

  function handleInputChange(value: string) {
    selectedQueryRef.current = '';
    requestSeqRef.current += 1;
    setQuery(value);
    setResults([]);
    setActiveIndex(-1);

    if (value.trim()) {
      setStatus('loading');
      setIsOpen(true);
    } else {
      setStatus('idle');
      setIsOpen(false);
    }
  }

  function handleFocus() {
    if (query.trim() && (results.length > 0 || status === 'loading' || status === 'empty' || status === 'error')) {
      setIsOpen(true);
    }
  }

  function handleKeyDown(event: React.KeyboardEvent<HTMLInputElement>) {
    if (event.key === 'Escape') {
      event.preventDefault();
      setIsOpen(false);
      setActiveIndex(-1);
      return;
    }

    if (event.key === 'ArrowDown' || event.key === 'ArrowUp') {
      event.preventDefault();
      if (!isOpen && query.trim()) setIsOpen(true);
      if (status !== 'success' || !results.length) return;

      setActiveIndex((current) => {
        if (event.key === 'ArrowDown') {
          return current < 0 ? 0 : (current + 1) % results.length;
        }
        return current < 0 ? results.length - 1 : (current - 1 + results.length) % results.length;
      });
      return;
    }

    if (event.key === 'Enter') {
      if (status !== 'success' || !isOpen || activeIndex < 0 || activeIndex >= results.length) return;
      event.preventDefault();
      selectOption(results[activeIndex]);
    }
  }

  function selectOption(value: string) {
    if (status !== 'success' || !results.includes(value)) return;
    selectedQueryRef.current = value;
    requestSeqRef.current += 1;
    setQuery(value);
    setResults([]);
    setStatus('idle');
    setIsOpen(false);
    setActiveIndex(-1);
    inputRef.current?.focus();
  }

  const visibleResults = status === 'success' ? results : [];
  const activeId = activeIndex >= 0 && visibleResults[activeIndex]
    ? optionId(visibleResults[activeIndex])
    : undefined;

  return (
    <main className="page">
      <section className="card" aria-labelledby="autocomplete-title">
        <div className="heading">
          <p className="eyebrow">React autocomplete interview question</p>
          <h1 id="autocomplete-title" className="title">Autocomplete search</h1>
          <p className="intro">Build debounce, stale-response handling, keyboard navigation, ARIA, and tests.</p>
        </div>

        <div ref={rootRef} className="combo">
          <label id={labelId} className="label" htmlFor="autocomplete-query">Search cities</label>
          <input
            ref={inputRef}
            id="autocomplete-query"
            className="input"
            role="combobox"
            aria-labelledby={labelId}
            aria-expanded={isOpen}
            aria-autocomplete="list"
            aria-controls={listboxId}
            aria-activedescendant={activeId}
            type="text"
            autoComplete="off"
            placeholder="Type san, sea, lon, or error"
            value={query}
            onChange={(event) => handleInputChange(event.target.value)}
            onFocus={handleFocus}
            onKeyDown={handleKeyDown}
          />

          {isOpen && (
            <ul className="list" id={listboxId} role="listbox" aria-label="City suggestions">
              {visibleResults.map((item, index) => (
                <li
                  key={item}
                  id={optionId(item)}
                  className={index === activeIndex ? 'option active' : 'option'}
                  role="option"
                  aria-selected={index === activeIndex}
                  onPointerDown={(event) => {
                    event.preventDefault();
                    selectOption(item);
                  }}
                >
                  {renderHighlighted(item, query)}
                </li>
              ))}
              {status === 'loading' && <li className="status">Loading suggestions for "{query.trim()}"...</li>}
              {status === 'empty' && <li className="status">No results</li>}
              {status === 'error' && <li className="status status--error">Search failed. Try a different query.</li>}
            </ul>
          )}
        </div>

        <p className="hint">Keep focus on the input. Use ArrowUp, ArrowDown, Enter, and Escape.</p>
      </section>
    </main>
  );
}

async function searchCities(rawQuery: string, signal: AbortSignal): Promise<string[]> {
  const query = rawQuery.trim().toLowerCase();
  const delay = query === 'san' ? 450 : query === 'se' ? 80 : 120;

  await sleep(delay, signal);

  if (query === 'error') {
    throw new Error('Deterministic search failure');
  }

  return CITIES
    .filter((city) => city.toLowerCase().includes(query))
    .slice(0, 8);
}

function renderHighlighted(item: string, rawQuery: string) {
  const query = rawQuery.trim();
  if (!query) return item;

  const index = item.toLowerCase().indexOf(query.toLowerCase());
  if (index < 0) return item;

  const before = item.slice(0, index);
  const match = item.slice(index, index + query.length);
  const after = item.slice(index + query.length);

  return (
    <>
      {before}
      <mark>{match}</mark>
      {after}
    </>
  );
}

